'use server'

import { revalidatePath } from 'next/cache'
import crypto from 'crypto'
import fs from 'fs'
import path from 'path'
import prisma from '@/lib/prisma'
import { verifySession } from '@/lib/session'

export async function uploadDocument(formData: FormData) {
  try {
    const session = await verifySession()
    if (!session || !session.userId) {
      return { success: false, error: 'Unauthorized user' }
    }

    const file = formData.get('file') as File | null
    const title = formData.get('title') as string
    const description = (formData.get('description') as string) || null

    if (!file || !title) {
      return { success: false, error: 'File and title are required' }
    }

    // 1. Convert file to buffer and calculate SHA-256 Hash
    const arrayBuffer = await file.arrayBuffer()
    const buffer = Buffer.from(arrayBuffer)
    const hashSum = crypto.createHash('sha256')
    hashSum.update(buffer)
    const currentHash = hashSum.digest('hex')

    // 2. Save file to public/uploads
    const uploadDir = path.join(process.cwd(), 'public', 'uploads')
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true })
    }
    const uniqueFilename = `${Date.now()}-${file.name}`
    const filePath = path.join(uploadDir, uniqueFilename)
    fs.writeFileSync(filePath, buffer)
    
    // Relative URL for frontend to access optionally (if wanted)
    const fileUrl = `/uploads/${uniqueFilename}`

    // 4. Create internal Document record and Audit Log transiton
    const document = await prisma.document.create({
      data: {
        title,
        description,
        fileUrl,
        currentHash,
        uploaderId: session.userId,
        history: {
          create: {
            action: 'UPLOADED',
            hashValue: currentHash,
            userId: session.userId,
            details: 'Original document uploaded'
          }
        }
      }
    })

    revalidatePath('/')
    return { success: true, document }
  } catch (error: any) {
    console.error('Error uploading document:', error)
    if (error.code === 'P2002') {
      return { success: false, error: 'A document with the exact same hash already exists' }
    }
    return { success: false, error: error.message || 'Error occurred' }
  }
}

export async function getDocuments() {
  const session = await verifySession()
  
  if (!session) return []

  // If COMPANY, only show their own documents
  if (session.role === 'COMPANY') {
    return await prisma.document.findMany({
      where: { uploaderId: session.userId },
      include: { uploader: true },
      orderBy: { createdAt: 'desc' }
    })
  }

  // If AUDITOR, show all documents cross-companies
  return await prisma.document.findMany({
    include: { uploader: true },
    orderBy: { createdAt: 'desc' }
  })
}

export async function getDocumentHistory(documentId: string) {
  return await prisma.auditLog.findMany({
    where: { documentId },
    include: { user: true },
    orderBy: { timestamp: 'desc' }
  })
}
